self.onmessage=async e=>{const{id:t,...s}=e.data;for(const e of Object.keys(s))self[e]=s[e];try{let e;if(t<0){const t=self.pyodide;importScripts(t);const s=t.replace(/\/[^/]*$/,"/");self.pyodide=await loadPyodide({indexURL:s}),await self.pyodide.loadPackage("micropip"),await self.pyodide.loadPackage("pydoc-data"),e=await self.pyodide.runPythonAsync("\n      import micropip\n      from js import packages, optlite\n      await micropip.install(optlite)\n      for p in packages:\n          await micropip.install(p)\n      ")}else await self.pyodide.loadPackagesFromImports(self.script),e=await self.pyodide.runPythonAsync("\n      import optlite\n      from js import script, rawInputLst\n      optlite.exec_script(script, rawInputLst)\n      ");self.postMessage({results:e,id:t})}catch(e){self.postMessage({error:"Failed to run code: "+e.message,id:t})}};